class PoolPilotDashboardCard extends HTMLElement {
  static getConfigElement(){return document.createElement('pool-pilot-dashboard-editor')}
  static getStubConfig(){return {title:'Piscine',theme:'flipr',show_weather:true,show_recommendations:true,enable_filter_pump:true,enable_heatpump:false,enable_electrolyzer:false,enable_counter_current:false,enable_pool_house:true}}
  setConfig(config){this.config={title:'Piscine',theme:'flipr',show_weather:true,show_recommendations:true,enable_filter_pump:true,enable_heatpump:false,enable_electrolyzer:false,enable_counter_current:false,enable_pool_house:false,ph_min:6.8,ph_max:7.8,chlorine_min:0,chlorine_max:5,orp_min:400,orp_max:900,...config};this._tab=this._tab||'analysis';if(!this.shadowRoot)this.attachShadow({mode:'open'})}
  set hass(hass){this._hass=hass;this.render()}
  getCardSize(){return 12}
  _state(e){return e&&this._hass?.states?.[e]?this._hass.states[e]:undefined}
  _value(e,f='—'){const s=this._state(e);if(!s||['unknown','unavailable','none','None',''].includes(String(s.state)))return f;return s.state}
  _num(e){const n=parseFloat(String(this._value(e,'')).replace(',','.'));return Number.isFinite(n)?n:null}
  _unit(e){return this._state(e)?.attributes?.unit_of_measurement||''}
  _format(e,f='—'){const v=this._value(e,f),u=this._unit(e);return v===f?v:`${v}${u?' '+u:''}`}
  _domain(e){return String(e||'').split('.')[0]}
  _isOn(e){return ['on','heat','heating','cool','auto','running'].includes(String(this._value(e,'off')).toLowerCase())}
  _key(s){return `pool-pilot-dashboard:${this.config?.title||'pool'}:${s}`}
  _until(k){const t=Number(localStorage.getItem(this._key(k))||0);return Number.isFinite(t)?t:0}
  _suppressed(){return Date.now()<Math.max(this._until('snooze'),this._until('done'))}
  _setSuppress(kind,hours){localStorage.setItem(this._key(kind),String(Date.now()+hours*3600000));if(kind==='done')this._callConfirm();this._showAlert=false;this.render()}
  _labelState(v){const m={safe:'Bon',ok:'Bon',good:'Bon',bon:'Bon',normal:'Bon',warning:'Attention',attention:'Attention',high:'Trop haut',low:'Trop bas',avoid:'Déconseillée',bad:'Mauvais',danger:'Danger',unknown:'Inconnu',unavailable:'Indisponible'};return m[String(v||'').toLowerCase()]||v||'—'}
  _qualityClass(v){const x=String(v||'').toLowerCase();if(['safe','ok','good','bon','normal'].includes(x))return 'good';if(['warning','attention','high','low'].includes(x))return 'warn';if(['avoid','bad','danger'].includes(x))return 'bad';return 'neutral'}
  _phStatus(v){const n=parseFloat(String(v).replace(',','.'));if(!Number.isFinite(n))return 'unknown';if(n<7.0)return 'low';if(n>7.4)return 'high';return 'good'}
  _chlStatus(){const c=this._num(this.config.chlorine_entity);if(c!==null){if(c<1)return'low';if(c>3)return'high';return'good'}const o=this._num(this.config.orp_entity);if(o!==null){if(o<650)return'low';if(o>800)return'high';return'good'}return'unknown'}
  _hasAlertRaw(){const c=this.config||{};if(!c.show_recommendations)return false;const actions=String(this._value(c.actions_entity,'')).trim().toLowerCase();const chem=String(this._value(c.chemistry_state_entity,'')).toLowerCase();const bath=String(this._value(c.bathing_state_entity,'')).toLowerCase();const hasAction=actions&&!['aucune recommandation','aucune action','ok','none','rien','ras','—'].includes(actions);const hasNeed=['warning','avoid','bad','danger','high','low'].includes(chem)||['high','low'].includes(this._phStatus(this._value(c.ph_entity,'')))||['high','low'].includes(this._chlStatus());return Boolean(hasAction||hasNeed||['warning','avoid','bad','danger'].includes(bath))}
  _hasAlert(){return this._hasAlertRaw()&&!this._suppressed()}
  _call(e,action='toggle',value=null){if(!e||!this._hass)return;const d=this._domain(e);if(d==='button'||d==='input_button')return this._hass.callService(d,'press',{entity_id:e});if(d==='script')return this._hass.callService('script','turn_on',{entity_id:e});if(d==='climate'){if(['heat','cool','auto'].includes(action))return this._hass.callService('climate','set_hvac_mode',{entity_id:e,hvac_mode:action});if(action==='set_temperature')return this._hass.callService('climate','set_temperature',{entity_id:e,temperature:value});return this._hass.callService('climate',action==='off'?'turn_off':action==='on'?'turn_on':'toggle',{entity_id:e})}if(['switch','input_boolean'].includes(d))return this._hass.callService(d,action==='on'?'turn_on':action==='off'?'turn_off':'toggle',{entity_id:e})}
  _callConfirm(){const c=this.config||{};if(c.confirm_action_entity)this._call(c.confirm_action_entity,'press');else if(this._hass)this._hass.callService('pool_pilot','confirm_product_added',{}).catch(()=>{})}
  _smallDevice(label,icon,entity){if(!entity)return'';return `<div class="device-mini"><ha-icon icon="${icon}"></ha-icon><span>${label}</span><strong>${this._isOn(entity)?'ON':'OFF'}</strong></div>`}
  _phGauge(value){const n=parseFloat(String(value).replace(',','.')),min=Number(this.config.ph_min||6.8),max=Number(this.config.ph_max||7.8);const pct=Number.isFinite(n)?Math.max(0,Math.min(1,(n-min)/(max-min))):.5;const deg=-135+pct*270,status=this._phStatus(value);return `<div class="gauge ph-gauge"><div class="ph-ring" style="--deg:${deg}deg"><div class="ph-line"></div><div class="ph-dot"></div><div class="gauge-value">${value||'—'}</div></div><div class="gauge-label">pH</div><div class="pill ${this._qualityClass(status)}"><ha-icon icon="mdi:alert-circle-outline"></ha-icon>${this._labelState(status)}</div></div>`}
  _chlorineGauge(){const raw=this._num(this.config.chlorine_entity)??this._num(this.config.orp_entity),isChl=Boolean(this.config.chlorine_entity);const min=Number(isChl?this.config.chlorine_min:this.config.orp_min)||(isChl?0:400),max=Number(isChl?this.config.chlorine_max:this.config.orp_max)||(isChl?5:900);const pct=raw===null?.5:Math.max(0,Math.min(1,(raw-min)/(max-min)));const left=Math.round(pct*100),status=this._chlStatus();const label=isChl?'Chlore':'RedOx';return `<div class="gauge chlorine-gauge"><div class="speed-title">${label}</div><div class="speed-meter"><div class="scale"><span>${min}</span><span>cible</span><span>${max}</span></div><div class="target-band"></div><div class="needle" style="left:${left}%"></div><div class="bubble" style="left:${left}%">${raw===null?'—':raw}</div></div><div class="pill ${this._qualityClass(status)}"><ha-icon icon="mdi:alert-circle-outline"></ha-icon>${this._labelState(status)}</div></div>`}
  _products(){const list=String(this.config.product_entities||'').split(',').map(x=>x.trim()).filter(Boolean);return list.map(e=>this._state(e)).filter(Boolean)}
  _productCard(s){const name=s.attributes.friendly_name||s.entity_id;const unit=s.attributes.unit_of_measurement||'';const low=String(s.attributes.stock_status||s.attributes.status||'').toLowerCase().includes('low')||s.attributes.stock_low===true;return `<div class="product ${low?'low':''}"><ha-icon icon="mdi:bottle-tonic-plus-outline"></ha-icon><div><strong>${name}</strong><span>Stock : ${s.state}${unit?' '+unit:''}</span></div><button data-service="restock" data-product="${s.attributes.product_id||name}">Réappro.</button></div>`}
  _alertPanel(){const c=this.config||{},actions=this._value(c.actions_entity,'Suivez les conseils ci-dessous pour résoudre le problème.');const phs=this._labelState(this._phStatus(this._value(c.ph_entity,'')));const title=phs==='Trop haut'?'Votre pH est trop élevé.':phs==='Trop bas'?'Votre pH est trop bas.':'Alerte en cours';return `<div class="modal-backdrop" data-close="1"><div class="alert-sheet"><button class="close" data-close="1"><ha-icon icon="mdi:close"></ha-icon></button><h1>Alerte en cours</h1><div class="alert-head"><ha-icon icon="mdi:alert-circle-outline"></ha-icon><strong>${title} - ${c.title||'Piscine'}</strong><span>Suivez les instructions puis validez l'ajout du produit.</span></div><div class="steps"><div><b>1</b><span>${actions}</span></div><div><b>2</b><span>Ajoutez la quantité indiquée dans votre bassin, filtration en fonctionnement.</span></div><div><b>3</b><span>Après validation, l'alerte sera masquée 24 h pour laisser le traitement agir.</span></div><div><b>4</b><span>Plus tard reporte uniquement l'alerte de 6 h.</span></div></div><div class="alert-actions"><button data-snooze="6">Plus tard</button><button class="done" data-done="24">C'est fait <ha-icon icon="mdi:check-circle-outline"></ha-icon></button></div></div></div>`}
  _controlPanel(){const c=this.config||{};const temp=this._num(c.heatpump_entity)??this._num(c.heatpump_temp_entity);return `<div class="control-panel">${c.enable_filter_pump?`<div class="control-device"><ha-icon icon="mdi:pool"></ha-icon><div><strong>Filtration</strong><span>${c.filtration_duration_entity?'Durée recommandée : '+this._format(c.filtration_duration_entity):'Pompe de filtration'}</span></div><div class="control-buttons"><button class="round ${this._isOn(c.pump_entity)?'on':''}" data-action="toggle" data-entity="${c.pump_entity||''}"><ha-icon icon="mdi:power"></ha-icon></button>${c.pump_auto_entity?`<button class="wide" data-action="press" data-entity="${c.pump_auto_entity}"><ha-icon icon="mdi:auto-mode"></ha-icon>Auto</button>`:''}</div></div>`:''}${c.enable_heatpump?`<div class="control-device"><ha-icon icon="mdi:heat-pump-outline"></ha-icon><div><strong>Pompe à chaleur</strong><span>${this._value(c.heatpump_entity,'Arrêt')}</span></div><button class="round ${this._isOn(c.heatpump_entity)?'on':''}" data-action="toggle" data-entity="${c.heatpump_entity||''}"><ha-icon icon="mdi:power"></ha-icon></button><div class="heat-controls"><button class="mode ${this._value(c.heatpump_entity)==='heat'?'active':''}" data-action="heat" data-entity="${c.heatpump_entity||''}">Chauffage</button><button class="mode ${this._value(c.heatpump_entity)==='auto'?'active':''}" data-action="auto" data-entity="${c.heatpump_entity||''}">Auto</button><button class="mode ${this._value(c.heatpump_entity)==='cool'?'active':''}" data-action="cool" data-entity="${c.heatpump_entity||''}">Refroid.</button><div class="temp"><button data-temp="-0.5" data-entity="${c.heatpump_entity||''}">−</button><strong>${temp??'—'}°C</strong><button data-temp="0.5" data-entity="${c.heatpump_entity||''}">+</button></div></div></div>`:''}${c.enable_electrolyzer?`<div class="control-device"><ha-icon icon="mdi:creation-outline"></ha-icon><div><strong>Électrolyseur</strong><span>Production chlore</span></div><button class="round ${this._isOn(c.electrolyzer_entity)?'on':''}" data-action="toggle" data-entity="${c.electrolyzer_entity||''}"><ha-icon icon="mdi:power"></ha-icon></button></div>`:''}${c.enable_counter_current?`<div class="control-device"><ha-icon icon="mdi:waves-arrow-right"></ha-icon><div><strong>Nage à contre-courant</strong><span>Commande auxiliaire</span></div><button class="round ${this._isOn(c.counter_current_entity)?'on':''}" data-action="toggle" data-entity="${c.counter_current_entity||''}"><ha-icon icon="mdi:power"></ha-icon></button></div>`:''}${!c.enable_filter_pump&&!c.enable_heatpump&&!c.enable_electrolyzer&&!c.enable_counter_current?'<div class="empty">Aucun équipement configuré.</div>':''}</div>`}
  _poolHousePanel(){const products=this._products();return `<div class="poolhouse"><div class="house-head"><ha-icon icon="mdi:home-variant-outline"></ha-icon><div><strong>Pool House</strong><span>Produits et stocks</span></div></div>${products.length?products.map(s=>this._productCard(s)).join(''):'<div class="empty">Ajoute les capteurs de stock dans l’éditeur visuel, champ “Produits Pool House”.</div>'}</div>`}
  render(){if(!this.shadowRoot||!this._hass)return;const c=this.config||{};const water=this._format(c.water_temp_entity),air=this._format(c.air_temp_entity),ph=this._value(c.ph_entity),uv=this._value(c.uv_entity,'0'),last=this._format(c.last_measure_entity,'—'),alert=this._hasAlert();const tabs=`<button class="tab ${this._tab==='analysis'?'active':''}" data-tab="analysis"><ha-icon icon="mdi:water-outline"></ha-icon>Analyse</button><button class="tab ${this._tab==='control'?'active':''}" data-tab="control"><ha-icon icon="mdi:toggle-switch-outline"></ha-icon>Contrôle</button>${c.enable_pool_house?`<button class="tab ${this._tab==='poolhouse'?'active':''}" data-tab="poolhouse"><ha-icon icon="mdi:home-variant-outline"></ha-icon>Pool House</button>`:''}`;const devices=[c.enable_filter_pump?this._smallDevice('Filtration','mdi:pool',c.pump_entity):'',c.enable_heatpump?this._smallDevice('PAC','mdi:heat-pump-outline',c.heatpump_entity):'',c.enable_electrolyzer?this._smallDevice('Électrolyseur','mdi:creation-outline',c.electrolyzer_entity):'',c.enable_counter_current?this._smallDevice('Nage','mdi:waves-arrow-right',c.counter_current_entity):''].join('');const analysis=`<div class="analysis-equipment">${devices||'<div class="device-mini muted"><ha-icon icon="mdi:plus"></ha-icon><span>Aucun équipement configuré</span></div>'}</div><div class="measure-card"><div class="trophy"><ha-icon icon="mdi:trophy-outline"></ha-icon></div><div><strong>Dernière mesure</strong><span>${last}</span></div><button data-action="press" data-entity="${c.trigger_measure_entity||''}" title="Déclencher/récupérer une mesure"><ha-icon icon="mdi:download-circle-outline"></ha-icon></button></div><div class="wave"><div class="water-main"><span>eau</span><strong>${water}</strong></div></div><div class="gauges">${this._phGauge(ph)}${this._chlorineGauge()}</div>`;this.shadowRoot.innerHTML=`<style>${this.styles()}</style><ha-card class="pool-card ${c.theme||'flipr'}"><div class="top"><div class="title">${c.title||'Piscine'}</div><div class="tabs">${tabs}</div>${c.show_weather?`<div class="weather"><span>air</span><strong>${air}</strong><span class="uv">UV ${uv}</span></div>`:''}</div>${this._tab==='analysis'?analysis:this._tab==='control'?this._controlPanel():this._poolHousePanel()}${alert?`<button class="bottom-alert" data-open-alert="1"><ha-icon icon="mdi:alert-circle-outline"></ha-icon>Alerte en cours, suivre nos instructions</button>`:''}${this._showAlert?this._alertPanel():''}</ha-card>`;this._bind()}
  _bind(){this.shadowRoot.querySelectorAll('.tab').forEach(el=>el.addEventListener('click',()=>{this._tab=el.dataset.tab;this._showAlert=false;this.render()}));this.shadowRoot.querySelectorAll('[data-action]').forEach(el=>el.addEventListener('click',()=>this._call(el.dataset.entity,el.dataset.action)));this.shadowRoot.querySelectorAll('[data-temp]').forEach(el=>el.addEventListener('click',()=>{const ent=el.dataset.entity;const cur=this._num(ent)??this._num(this.config.heatpump_temp_entity)??26;this._call(ent,'set_temperature',cur+Number(el.dataset.temp))}));this.shadowRoot.querySelectorAll('[data-open-alert]').forEach(el=>el.addEventListener('click',()=>{this._showAlert=true;this.render()}));this.shadowRoot.querySelectorAll('[data-close]').forEach(el=>el.addEventListener('click',e=>{if(e.target===el||el.classList.contains('close')){this._showAlert=false;this.render()}}));this.shadowRoot.querySelectorAll('[data-snooze]').forEach(el=>el.addEventListener('click',()=>this._setSuppress('snooze',Number(el.dataset.snooze||6))));this.shadowRoot.querySelectorAll('[data-done]').forEach(el=>el.addEventListener('click',()=>this._setSuppress('done',Number(el.dataset.done||24))));this.shadowRoot.querySelectorAll('[data-service="restock"]').forEach(el=>el.addEventListener('click',()=>this._hass.callService('pool_pilot','update_product_stock',{product_id:el.dataset.product}).catch(()=>{})))}
  styles(){return `:host{display:block}.pool-card{position:relative;overflow:hidden;border-radius:24px;background:linear-gradient(180deg,#2ed5c7 0%,#3289d7 58%,#fff 58%,#fff 100%);color:white;font-family:var(--paper-font-body1_-_font-family,Roboto,Arial);min-height:680px}.top{padding:18px}.title{font-size:28px;font-weight:800;margin-bottom:12px}.tabs{display:flex;gap:6px;flex-wrap:wrap}.tab{border:0;border-radius:999px;background:rgba(255,255,255,.18);color:white;padding:8px 10px;font-weight:700;display:flex;gap:4px;align-items:center}.tab.active{background:white;color:#143150}.weather{position:absolute;right:18px;top:18px;text-align:right}.weather span{display:block;font-size:12px;opacity:.8}.weather strong{font-size:20px}.uv{background:rgba(255,255,255,.2);border-radius:12px;padding:4px 8px;margin-top:3px}.analysis-equipment{padding:0 18px;display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.device-mini{background:rgba(255,255,255,.18);border-radius:16px;padding:10px;display:flex;align-items:center;gap:8px}.device-mini strong{margin-left:auto}.measure-card{margin:12px 18px;background:white;color:#14233b;border-radius:18px;padding:12px;display:grid;grid-template-columns:44px 1fr 44px;align-items:center;box-shadow:0 8px 28px rgba(0,0,0,.15)}.measure-card span{display:block;color:#6b788b;font-size:12px}.measure-card button{border:0;background:#eef4f9;border-radius:50%;height:40px}.trophy{background:#ffe7a6;border-radius:50%;height:42px;display:flex;align-items:center;justify-content:center;color:#8a6200}.wave{height:125px;display:flex;align-items:center;justify-content:center}.water-main{text-align:center}.water-main span{display:block}.water-main strong{font-size:50px}.gauges{background:white;color:#14233b;border-radius:28px 28px 0 0;padding:22px 12px 28px;display:grid;grid-template-columns:1fr 1fr;gap:10px;min-height:260px}.gauge{text-align:center;display:flex;flex-direction:column;align-items:center;gap:8px}.ph-ring{--deg:0deg;width:132px;height:132px;border-radius:50%;position:relative;background:conic-gradient(from 225deg,#14233b 0 270deg,transparent 270deg 360deg);display:flex;align-items:center;justify-content:center}.ph-ring:after{content:"";position:absolute;inset:13px;border-radius:50%;background:linear-gradient(160deg,#31c9cc,#4aa6d7)}.ph-line{position:absolute;left:50%;top:50%;width:3px;height:62px;background:#0c1322;border-radius:3px;transform:rotate(var(--deg)) translateY(-62px);transform-origin:50% 100%;z-index:3}.ph-dot{position:absolute;left:50%;top:50%;width:21px;height:21px;background:white;border-radius:50%;box-shadow:0 2px 6px rgba(0,0,0,.25);transform:rotate(var(--deg)) translate(0,-62px);transform-origin:center;z-index:4}.gauge-value{position:relative;z-index:5;font-size:38px;color:white}.gauge-label,.speed-title{font-size:20px;font-weight:700}.speed-meter{width:150px;height:82px;position:relative;margin:10px 0 4px}.scale{position:absolute;left:0;right:0;top:56px;display:flex;justify-content:space-between;font-size:11px;color:#6b788b}.target-band{position:absolute;left:30%;right:30%;top:36px;height:14px;border-radius:8px;background:#12213a}.target-band:before,.target-band:after{content:"";position:absolute;top:-8px;height:30px;width:2px;background:#12213a}.target-band:before{left:0}.target-band:after{right:0}.needle{position:absolute;top:20px;width:4px;height:44px;background:#fff;border:2px solid #12213a;border-radius:5px;transform:translateX(-50%);z-index:3}.bubble{position:absolute;top:-8px;transform:translateX(-50%);background:white;color:#11182d;border:2px solid #11182d;border-radius:50%;width:42px;height:42px;display:flex;align-items:center;justify-content:center;font-weight:800;z-index:4}.pill{border-radius:999px;padding:8px 14px;min-width:110px;text-align:center;font-size:15px;background:#eef4f8;color:#14233b;display:flex;justify-content:center;align-items:center;gap:6px}.pill.good{background:#e8fbf7;color:#0c7b69}.pill.warn{background:#fff3dd;color:#9b5a00}.pill.bad{background:#ff8b4d;color:white}.bottom-alert{width:100%;border:0;display:flex;align-items:center;justify-content:center;gap:10px;background:#ff8b4d;color:white;padding:15px 12px;font-weight:800;font-size:17px}.control-panel,.poolhouse{padding:18px;color:#14233b;background:white;min-height:490px}.control-device,.product,.house-head{display:grid;grid-template-columns:54px 1fr auto;align-items:center;gap:12px;background:#f6f8fb;border-radius:16px;padding:16px 14px;margin-bottom:14px}.control-device>ha-icon,.product>ha-icon,.house-head>ha-icon{--mdc-icon-size:40px;color:#111}.control-device span,.product span,.house-head span{display:block;font-size:13px;color:#536176;margin-top:4px}.product.low{border:2px solid #ff8b4d}.product button{border:0;border-radius:999px;background:#10182d;color:white;padding:9px 12px;font-weight:800}.control-buttons{display:flex;gap:8px}.round{width:42px;height:42px;border-radius:50%;border:0;background:#edf1f7;color:#98a5b8;display:flex;align-items:center;justify-content:center}.round.on{background:#16d26b;color:white}.wide{border:0;border-radius:999px;background:#10182d;color:white;padding:10px 12px;font-weight:800;display:flex;gap:5px;align-items:center}.heat-controls{grid-column:1/-1;display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-top:8px}.mode{border:0;border-radius:12px;background:#edf1f7;color:#536176;padding:10px 8px;font-weight:700}.mode.active{background:#10182d;color:white}.temp{grid-column:1/-1;display:grid;grid-template-columns:44px 1fr 44px;align-items:center;gap:10px;background:#f3f6fa;border-radius:14px;padding:6px}.temp button{border:0;border-radius:10px;background:white;color:#10182d;font-size:22px}.temp strong{text-align:center;font-size:22px}.empty{padding:30px;text-align:center;color:#617086}.modal-backdrop{position:absolute;inset:0;background:rgba(0,0,0,.25);z-index:10;display:flex;align-items:flex-end}.alert-sheet{position:relative;background:white;color:#14233b;border-radius:24px 24px 0 0;padding:24px 18px;max-height:92%;overflow:auto}.alert-sheet h1{font-size:34px;margin:0 0 18px}.close{position:absolute;right:18px;top:18px;border:0;background:#eef1f6;border-radius:50%;width:42px;height:42px}.alert-head{background:#203b50;color:white;border-radius:8px;padding:18px;text-align:center;display:flex;flex-direction:column;gap:8px}.alert-head ha-icon{color:#ff3f65;margin:auto;--mdc-icon-size:52px}.steps{margin:22px 0;display:grid;gap:16px}.steps div{display:grid;grid-template-columns:46px 1fr;gap:14px;align-items:center}.steps b{background:#203b50;color:white;padding:15px 0;text-align:center}.steps span{background:white;border-radius:10px;padding:15px;box-shadow:0 3px 14px rgba(22,42,70,.18)}.alert-actions{display:grid;grid-template-columns:1fr 1fr;gap:18px}.alert-actions button{border:0;border-radius:999px;padding:14px;font-weight:800;background:#dddaf3;color:#203b50}.alert-actions .done{background:#32d8b9;color:white;display:flex;align-items:center;justify-content:center;gap:8px}@media(max-width:430px){.analysis-equipment{grid-template-columns:1fr}.gauges{gap:6px}.ph-ring{width:116px;height:116px}.ph-line{height:55px;transform:rotate(var(--deg)) translateY(-55px)}.ph-dot{transform:rotate(var(--deg)) translate(0,-55px)}.speed-meter{width:132px}.pill{min-width:100px;font-size:14px}.control-device,.product,.house-head{grid-template-columns:44px 1fr auto}.heat-controls{grid-column:1/-1}}`}
}

class PoolPilotDashboardEditor extends HTMLElement {
  setConfig(config){this.config={theme:'flipr',show_weather:true,show_recommendations:true,enable_filter_pump:true,enable_heatpump:false,enable_electrolyzer:false,enable_counter_current:false,enable_pool_house:false,ph_min:6.8,ph_max:7.8,chlorine_min:0,chlorine_max:5,orp_min:400,orp_max:900,...config};this.render()}
  set hass(hass){this._hass=hass;this.render()}
  _schema(){const s=[{name:'title',selector:{text:{}}},{name:'theme',selector:{select:{options:[{value:'flipr',label:'Flipr Classic'},{value:'dark',label:'Sombre'},{value:'ha',label:'Home Assistant'}]}}},{name:'water_temp_entity',selector:{entity:{domain:'sensor'}}},{name:'air_temp_entity',selector:{entity:{domain:'sensor'}}},{name:'uv_entity',selector:{entity:{domain:'sensor'}}},{name:'ph_entity',selector:{entity:{domain:'sensor'}}},{name:'chlorine_entity',selector:{entity:{domain:'sensor'}}},{name:'orp_entity',selector:{entity:{domain:'sensor'}}},{name:'last_measure_entity',selector:{entity:{domain:['sensor','input_datetime']}}},{name:'trigger_measure_entity',selector:{entity:{domain:['button','input_button','switch']}}},{name:'chemistry_state_entity',selector:{entity:{domain:'sensor'}}},{name:'bathing_state_entity',selector:{entity:{domain:'sensor'}}},{name:'actions_entity',selector:{entity:{domain:'sensor'}}},{name:'confirm_action_entity',selector:{entity:{domain:['button','input_button']}}},{name:'enable_filter_pump',selector:{boolean:{}}}];if(this.config?.enable_filter_pump)s.push({name:'pump_entity',selector:{entity:{domain:['switch','input_boolean']}}},{name:'pump_auto_entity',selector:{entity:{domain:['button','input_button','switch','script']}}},{name:'filtration_duration_entity',selector:{entity:{domain:'sensor'}}});s.push({name:'enable_heatpump',selector:{boolean:{}}});if(this.config?.enable_heatpump)s.push({name:'heatpump_entity',selector:{entity:{domain:['climate','switch','input_boolean']}}},{name:'heatpump_temp_entity',selector:{entity:{domain:'sensor'}}});s.push({name:'enable_electrolyzer',selector:{boolean:{}}});if(this.config?.enable_electrolyzer)s.push({name:'electrolyzer_entity',selector:{entity:{domain:['switch','input_boolean']}}});s.push({name:'enable_counter_current',selector:{boolean:{}}});if(this.config?.enable_counter_current)s.push({name:'counter_current_entity',selector:{entity:{domain:['switch','input_boolean']}}});s.push({name:'enable_pool_house',selector:{boolean:{}}});if(this.config?.enable_pool_house)s.push({name:'product_entities',selector:{text:{multiline:true}}});s.push({name:'show_weather',selector:{boolean:{}}},{name:'show_recommendations',selector:{boolean:{}}},{name:'ph_min',selector:{number:{min:6,max:8,step:.1,mode:'box'}}},{name:'ph_max',selector:{number:{min:7,max:9,step:.1,mode:'box'}}},{name:'chlorine_min',selector:{number:{min:0,max:10,step:.1,mode:'box'}}},{name:'chlorine_max',selector:{number:{min:0,max:10,step:.1,mode:'box'}}});return s}
  _labels(){return {title:'Titre',theme:'Thème',water_temp_entity:'Température eau',air_temp_entity:'Température air',uv_entity:'Indice UV',ph_entity:'pH',chlorine_entity:'Chlore libre',orp_entity:'RedOx / ORP',last_measure_entity:'Date/heure dernière mesure Flipr',trigger_measure_entity:'Bouton déclencher/récupérer mesure',chemistry_state_entity:'État chimie',bathing_state_entity:'État baignade',actions_entity:'Actions / besoins produits',confirm_action_entity:'Bouton validation action',enable_filter_pump:'Ajouter la filtration',pump_entity:'Commande on/off pompe filtration',pump_auto_entity:'Bouton/script filtration auto recommandée',filtration_duration_entity:'Durée filtration recommandée',enable_heatpump:'Ajouter la pompe à chaleur',heatpump_entity:'Entité PAC climate',heatpump_temp_entity:'Température/consigne PAC',enable_electrolyzer:"Ajouter l'électrolyseur",electrolyzer_entity:'Commande électrolyseur',enable_counter_current:'Ajouter la nage à contre-courant',counter_current_entity:'Commande nage à contre-courant',enable_pool_house:'Ajouter le Pool House',product_entities:'Produits Pool House, entités séparées par des virgules',show_weather:'Afficher météo',show_recommendations:'Afficher alertes/recommandations',ph_min:'pH minimum jauge',ph_max:'pH maximum jauge',chlorine_min:'Chlore minimum jauge',chlorine_max:'Chlore maximum jauge'}}
  render(){if(!this._hass)return;if(!this.shadowRoot)this.attachShadow({mode:'open'});this.shadowRoot.innerHTML='<style>.editor{padding:12px 0}.hint{color:var(--secondary-text-color);font-size:13px;margin:0 0 12px}</style><div class="editor"><p class="hint">Coche les équipements présents : seuls les champs utiles apparaissent. Pour le Pool House, liste les capteurs de stock séparés par des virgules.</p><ha-form></ha-form></div>';const form=this.shadowRoot.querySelector('ha-form');form.hass=this._hass;form.data=this.config;form.schema=this._schema();form.computeLabel=s=>this._labels()[s.name]||s.name;form.addEventListener('value-changed',ev=>{this.config=ev.detail.value;this.render();this.dispatchEvent(new CustomEvent('config-changed',{detail:{config:this.config},bubbles:true,composed:true}))})}
}
